import{_ as a,o as t,c as n,ag as r}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Bedrijfsinstellingen","description":"","frontmatter":{},"headers":[],"relativePath":"nl/settings/company.md","filePath":"nl/settings/company.md"}'),i={name:"nl/settings/company.md"};function o(l,e,s,d,g,u){return t(),n("div",null,[...e[0]||(e[0]=[r('<h1 id="bedrijfsinstellingen" tabindex="-1">Bedrijfsinstellingen <a class="header-anchor" href="#bedrijfsinstellingen" aria-label="Permalink to &quot;Bedrijfsinstellingen&quot;">​</a></h1><p>Configureer je bedrijfsinformatie, huisstijl, financiele standaardwaarden en ingeschakelde functies.</p><h2 id="instellingen-openen" tabindex="-1">Instellingen openen <a class="header-anchor" href="#instellingen-openen" aria-label="Permalink to &quot;Instellingen openen&quot;">​</a></h2><p>Navigeer naar <strong>Bedrijf</strong> in de zijbalk om alle bedrijfsinstellingen te openen. De instellingen zijn georganiseerd in secties.</p><h2 id="bedrijfsinformatie" tabindex="-1">Bedrijfsinformatie <a class="header-anchor" href="#bedrijfsinformatie" aria-label="Permalink to &quot;Bedrijfsinformatie&quot;">​</a></h2><h3 id="bedrijfsgegevens" tabindex="-1">Bedrijfsgegevens <a class="header-anchor" href="#bedrijfsgegevens" aria-label="Permalink to &quot;Bedrijfsgegevens&quot;">​</a></h3><ul><li><strong>Bedrijfsnaam</strong> — Je geregistreerde handelsnaam (verschijnt op alle documenten)</li><li><strong>Adres</strong> — Straat, postcode, plaats, land</li><li><strong>Contacte-mail</strong> — Primair zakelijk e-mailadres</li><li><strong>Telefoon</strong> — Zakelijk telefoonnummer</li></ul><h3 id="registratie" tabindex="-1">Registratie <a class="header-anchor" href="#registratie" aria-label="Permalink to &quot;Registratie&quot;">​</a></h3><ul><li><strong>BTW-nummer</strong> — Je BTW-registratie (bijv. NL123456789B01)</li><li><strong>KVK-nummer</strong> — Bedrijfsregistratienummer</li><li><strong>IBAN</strong> — Bankrekening voor het ontvangen van betalingen</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Adresaanvulling is beschikbaar — begin met typen en selecteer uit suggesties aangestuurd door Google Maps.</p></div><h2 id="huisstijl" tabindex="-1">Huisstijl <a class="header-anchor" href="#huisstijl" aria-label="Permalink to &quot;Huisstijl&quot;">​</a></h2><h3 id="logo" tabindex="-1">Logo <a class="header-anchor" href="#logo" aria-label="Permalink to &quot;Logo&quot;">​</a></h3><p>Upload je bedrijfslogo voor gebruik op:</p><ul><li>Factuur- en offerte-PDF&#39;s</li><li>E-mailcommunicatie</li><li>Klantportaal</li><li>Openbare bedrijfspagina</li></ul><p>Ondersteunde formaten: PNG, JPG, SVG. Gebruik een afbeelding met hoge resolutie en transparante achtergrond voor het beste resultaat.</p><h3 id="kleuren" tabindex="-1">Kleuren <a class="header-anchor" href="#kleuren" aria-label="Permalink to &quot;Kleuren&quot;">​</a></h3><p>Stel je merk-accentkleur in. Deze wordt gebruikt op:</p><ul><li>PDF-documenten</li><li>E-mailsjablonen</li><li>Klantgerichte pagina&#39;s</li></ul><h2 id="financiele-standaardwaarden" tabindex="-1">Financiele standaardwaarden <a class="header-anchor" href="#financiele-standaardwaarden" aria-label="Permalink to &quot;Financiele standaardwaarden&quot;">​</a></h2><h3 id="valuta" tabindex="-1">Valuta <a class="header-anchor" href="#valuta" aria-label="Permalink to &quot;Valuta&quot;">​</a></h3><p>Stel je standaardvaluta in (standaard EUR). Dit geldt voor nieuwe facturen en offertes.</p><h3 id="betalingstermijn" tabindex="-1">Betalingstermijn <a class="header-anchor" href="#betalingstermijn" aria-label="Permalink to &quot;Betalingstermijn&quot;">​</a></h3><p>Stel het standaard aantal dagen in tot een factuur vervalt. Veelgebruikte waarden:</p><ul><li><strong>14 dagen</strong> — Twee weken</li><li><strong>30 dagen</strong> — Een maand</li><li><strong>60 dagen</strong> — Twee maanden</li></ul><p>Je kunt dit per factuur overschrijven.</p><h3 id="factuurnummering" tabindex="-1">Factuurnummering <a class="header-anchor" href="#factuurnummering" aria-label="Permalink to &quot;Factuurnummering&quot;">​</a></h3><p>Pas aan hoe factuurnummers worden gegenereerd:</p><ul><li><strong>Voorvoegsel</strong> — Tekst voor het nummer (bijv. <code>INV-</code>, <code>2024-</code>)</li><li><strong>Startnummer</strong> — Het eerste nummer in de reeks</li><li><strong>Automatische ophoging</strong> — Nummers worden automatisch verhoogd</li></ul><h2 id="functiemodules-aan-uit" tabindex="-1">Functiemodules aan/uit <a class="header-anchor" href="#functiemodules-aan-uit" aria-label="Permalink to &quot;Functiemodules aan/uit&quot;">​</a></h2><p>Schakel optionele modules in of uit:</p><table tabindex="0"><thead><tr><th>Functie</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Objecten / Activa</strong></td><td>Verhuur- en activabeheer</td></tr><tr><td><strong>Contracten</strong></td><td>Terugkerende service- en huurcontracten</td></tr><tr><td><strong>Projecten</strong></td><td>Projectmatig werken bijhouden</td></tr><tr><td><strong>Offertes</strong></td><td>Offertebeheer</td></tr><tr><td><strong>Verlegde BTW</strong></td><td>Intra-EU B2B-facturatie</td></tr><tr><td><strong>AI-suggesties</strong></td><td>Slimme categorisatie-aanbevelingen</td></tr><tr><td><strong>Bonnen scannen</strong></td><td>OCR-uitgaveninvoer</td></tr><tr><td><strong>Tekstcontrole</strong></td><td>Grammatica- en spellingcontrole</td></tr></tbody></table><p>Uitgeschakelde modules worden verborgen uit de navigatie om je werkruimte overzichtelijk te houden.</p><h2 id="pdf-sjabloon" tabindex="-1">PDF-sjabloon <a class="header-anchor" href="#pdf-sjabloon" aria-label="Permalink to &quot;PDF-sjabloon&quot;">​</a></h2><p>Pas de lay-out en het uiterlijk van je gegenereerde PDF&#39;s aan:</p><ul><li>Veldpositionering</li><li>Informatiezichtbaarheid</li><li>Lettertype en grootte</li><li>Logoplaatsing</li></ul><p>Open de volledige <strong>PDF-editor</strong> voor visuele drag-and-drop-aanpassing via Bedrijf &gt; PDF-editor.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Geavanceerde PDF-aanpassing vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h2 id="teamleden" tabindex="-1">Teamleden <a class="header-anchor" href="#teamleden" aria-label="Permalink to &quot;Teamleden&quot;">​</a></h2><p>Bekijk en beheer je team vanaf de bedrijfspagina. Zie <a href="/nl/settings/team">Teambeheer</a> voor details.</p>',39)])])}const m=a(i,[["render",o]]);export{h as __pageData,m as default};
